         * Constructs a new YAML parsing exception with the specified detail message.
         * 
         * @param message the detail message
         */
        public YamlParsingException(String message) {
            super(message);
        }

        /**
         * Constructs a new YAML parsing exception with the specified detail message and cause.
         * 
         * @param message the detail message
         * @param cause the underlying cause of the exception
         */
        public YamlParsingException(String message, Throwable cause) {
            super(message, cause);
        }
    }
